sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var result = { status: "success" };

    var type   = '' + (request.queryParams.type   && request.queryParams.type[0]   || 'metadata');
    var search = '' + (request.queryParams.search && request.queryParams.search[0] || '');
    var limit  = parseInt('' + (request.queryParams.limit && request.queryParams.limit[0] || 100)) || 100;

    try {
        if (type === 'metadata') {
            result.states = [];
            result.urgencies = [];
            result.incident_fields = [];
            result.groups = [];
            result.configuration_items = [];

            // Fetch Incident States
            var stateGR = new GlideRecord('sys_choice');
            stateGR.addQuery('name', 'incident');
            stateGR.addQuery('element', 'state');
            stateGR.query();
            while (stateGR.next()) {
                result.states.push({
                    label: stateGR.label.toString(),
                    value: stateGR.value.toString(),
                    sys_id: stateGR.sys_id.toString()
                });
            }

            // Fetch Incident Urgency
            var urgencyGR = new GlideRecord('sys_choice');
            urgencyGR.addQuery('name', 'task');
            urgencyGR.addQuery('element', 'urgency');
            urgencyGR.query();
            while (urgencyGR.next()) {
                result.urgencies.push({
                    label: urgencyGR.label.toString(),
                    value: urgencyGR.value.toString(),
                    sys_id: urgencyGR.sys_id.toString()
                });
            }

            // Fetch All Incident Fields
            var addedFields = {};
            var tables = ['task', 'incident'];
            for (var i = 0; i < tables.length; i++) {
                var dictGR = new GlideRecord('sys_dictionary');
                dictGR.addQuery('name', tables[i]);
                dictGR.addQuery('internal_type', '!=', 'collection');
                dictGR.query();
                while (dictGR.next()) {
                    var fieldName = dictGR.element.toString();
                    if (!addedFields[fieldName]) {
                        result.incident_fields.push({
                            name: fieldName,
                            label: dictGR.getDisplayValue('column_label')
                        });
                        addedFields[fieldName] = true;
                    }
                }
            }

            // Fetch Assignment Groups (limit)
            var groupGR = new GlideRecord('sys_user_group');
            groupGR.setLimit(limit);
            groupGR.query();
            while (groupGR.next()) {
                result.groups.push({
                    name:   groupGR.name.toString(),
                    sys_id: groupGR.sys_id.toString()
                });
            }

            // Fetch Configuration Items (limit)
            var ciGR = new GlideRecord('cmdb_ci');
            ciGR.setLimit(limit);
            ciGR.query();
            while (ciGR.next()) {
                result.configuration_items.push({
                    name:   ciGR.name.toString(),
                    sys_id: ciGR.sys_id.toString(),
                    class:  ciGR.sys_class_name.toString()
                });
            }

        } else if (type === 'groups') {
            result.groups = [];

            var groupGR = new GlideRecord('sys_user_group');
            if (search) {
                groupGR.addEncodedQuery('nameCONTAINS' + search);
            }
            groupGR.setLimit(limit);
            groupGR.query();
            while (groupGR.next()) {
                result.groups.push({
                    name:   groupGR.name.toString(),
                    sys_id: groupGR.sys_id.toString()
                });
            }
            if (search) {
                var lowerSearch = search.toLowerCase();
                result.groups.sort(function(a, b) {
                    var aExact = a.name.toLowerCase() === lowerSearch ? 0 : 1;
                    var bExact = b.name.toLowerCase() === lowerSearch ? 0 : 1;
                    return aExact - bExact;
                });
            }

        } else if (type === 'configuration_items') {
            result.configuration_items = [];

            var ciGR = new GlideRecord('cmdb_ci');
            if (search) {
                ciGR.addEncodedQuery('nameCONTAINS' + search);
            }
            ciGR.setLimit(limit);
            ciGR.query();
            while (ciGR.next()) {
                result.configuration_items.push({
                    name:   ciGR.name.toString(),
                    sys_id: ciGR.sys_id.toString(),
                    class:  ciGR.sys_class_name.toString()
                });
            }
            if (search) {
                var lowerSearchCI = search.toLowerCase();
                result.configuration_items.sort(function(a, b) {
                    var aExact = a.name.toLowerCase() === lowerSearchCI ? 0 : 1;
                    var bExact = b.name.toLowerCase() === lowerSearchCI ? 0 : 1;
                    return aExact - bExact;
                });
            }

        } else {
            response.setStatus(400);
            return { status: "error", message: "Invalid type. Use: metadata | groups | configuration_items" };
        }

        response.setStatus(200);
        return result;

    } catch (e) {
        response.setStatus(400);
        return { status: "error", message: e.message || "Unexpected error." };
    }

})(request, response);
